diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index d08be1e55c85..f3da28ca6cba 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1273,6 +1273,21 @@ Value *llvm::simplifySDivInst(Value *Op0, Value *Op1, bool IsExact,
 /// If not, this returns null.
 static Value *simplifyUDivInst(Value *Op0, Value *Op1, bool IsExact,
                                const SimplifyQuery &Q, unsigned MaxRecurse) {
+  // Check if the divisor is derived from a select instruction.
+  if (SelectInst *SI = dyn_cast<SelectInst>(Op1)) {
+    Value *TrueVal = SI->getTrueValue();
+    Value *FalseVal = SI->getFalseValue();
+
+    // Ensure neither branch of the select produces a zero divisor.
+    KnownBits KnownTrue = computeKnownBits(TrueVal, /* Depth */ 0, Q);
+    KnownBits KnownFalse = computeKnownBits(FalseVal, /* Depth */ 0, Q);
+
+    if (KnownTrue.isZero() || KnownFalse.isZero()) {
+      // If either branch can be zero, return nullptr to avoid incorrect simplification.
+      return nullptr;
+    }
+  }
+
   return simplifyDiv(Instruction::UDiv, Op0, Op1, IsExact, Q, MaxRecurse);
 }

